# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from functools import wraps
from datetime import datetime

app = Flask(__name__)

# Mock database (replace with actual database in production)
users_db = {
    1: {
        'id': 1,
        'username': 'admin',
        'email': 'admin@example.com',
        'role': 'admin',
        'account_status': 'active',
        'subscription_tier': 'enterprise',
        'updated_at': None
    },
    2: {
        'id': 2,
        'username': 'user1',
        'email': 'user1@example.com',
        'role': 'user',
        'account_status': 'active',
        'subscription_tier': 'free',
        'updated_at': None
    }
}

# Mock current_user (replace with actual session/auth in production)
current_user = users_db[1]

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user or current_user.get('role') != 'admin':
            return jsonify({'error': 'Unauthorized. Admin access required.'}), 403
        return f(*args, **kwargs)
    return decorated_function

def validate_email(email):
    return '@' in email and '.' in email.split('@')[1]

def validate_role(role):
    return role in ['user', 'moderator', 'admin']

def validate_account_status(status):
    return status in ['active', 'suspended']

def validate_subscription_tier(tier):
    return tier in ['free', 'pro', 'enterprise']

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    if user_id not in users_db:
        return jsonify({'error': 'User not found'}), 404
    
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    user = users_db[user_id]
    errors = []
    
    # Validate and update email
    if 'email' in data:
        email = data['email']
        if not email or not validate_email(email):
            errors.append('Invalid email format')
        else:
            # Check if email already exists for another user
            for uid, u in users_db.items():
                if uid != user_id and u['email'] == email:
                    errors.append('Email already in use')
                    break
            if not errors:
                user['email'] = email
    
    # Validate and update username
    if 'username' in data:
        username = data['username']
        if not username or len(username) < 3:
            errors.append('Username must be at least 3 characters long')
        else:
            # Check if username already exists for another user
            for uid, u in users_db.items():
                if uid != user_id and u['username'] == username:
                    errors.append('Username already in use')
                    break
            if not errors or (len(errors) == 0):
                user['username'] = username
    
    # Validate and update role
    if 'role' in data:
        role = data['role']
        if not validate_role(role):
            errors.append('Invalid role. Must be one of: user, moderator, admin')
        else:
            user['role'] = role
    
    # Validate and update account_status
    if 'account_status' in data:
        account_status = data['account_status']
        if not validate_account_status(account_status):
            errors.append('Invalid account status. Must be one of: active, suspended')
        else:
            user['account_status'] = account_status
    
    # Validate and update subscription_tier
    if 'subscription_tier' in data:
        subscription_tier = data['subscription_tier']
        if not validate_subscription_tier(subscription_tier):
            errors.append('Invalid subscription tier. Must be one of: free, pro, enterprise')
        else:
            user['subscription_tier'] = subscription_tier
    
    if errors:
        return jsonify({'error': 'Validation failed', 'details': errors}), 400
    
    # Update timestamp
    user['updated_at'] = datetime.utcnow().isoformat()
    
    return jsonify({
        'message': 'User updated successfully',
        'user': user
    }), 200

if __name__ == '__main__':
    app.run(debug=True)